```typescript
@Controller('upload-files')
@UseGuards(AuthGuard) @SkipPermission()
export class UploadFileController {
  @Post()
  @AuditLog({ module: AuditModule.UPLOAD, event: 'UPLOAD_FILE', description: '上传文件' })
  @UseInterceptors(FileInterceptor('file'))
  async upload(@UploadedFile() file: Express.Multer.File, @Query('businessType') businessType?: string) {
    return this.uploadFileService.upload(file, businessType);
  }
}
```

